package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithAllowMissingColumnNames() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withAllowMissingColumnNames();
        assertNotNull(result);
        assertTrue(result.getAllowMissingColumnNames());
        // The original instance should remain unchanged (immutable pattern)
        assertFalse(format.getAllowMissingColumnNames());
        // Using withAllowMissingColumnNames(true) explicitly should be equal to withAllowMissingColumnNames()
        CSVFormat explicit = format.withAllowMissingColumnNames(true);
        assertEquals(explicit, result);
    }
}
